// var leaks out of the block
function processItems(items) {
  for (var i = 0; i < items.length; i++) {
    var item = items[i];   // 'item' and 'i' are function-scoped
    // ... process item
  }
  console.log(i);    // 3  — still accessible after the loop
  console.log(item); // last item — not block-local
}

// var hoisting
console.log(name);  // undefined  (no error — var was hoisted)
var name = 'Alice'; // assignment happens here

function processItems(items) {
  for (let i = 0; i < items.length; i++) {
    let item = items[i];   // block-scoped to loop body
    // ...
  }
  // console.log(i);    // ReferenceError — i is not defined here
  // console.log(item); // ReferenceError
}

// Temporal Dead Zone (TDZ)
// console.log(count); // ReferenceError — TDZ: let is hoisted but NOT initialized
let count = 0;
console.log(count); // 0  — now accessible

// var — all callbacks share the SAME i
for (var i = 0; i < 3; i++) {
  setTimeout(() => console.log(i), 0); // prints 3, 3, 3
}

// let — each iteration has its own i
for (let i = 0; i < 3; i++) {
  setTimeout(() => console.log(i), 0); // prints 0, 1, 2
}

