function makeAdder(x) {
  return function(y) {
    return x + y; // closes over x from the outer scope
  };
}

const add5 = makeAdder(5);
const add10 = makeAdder(10);

console.log(add5(3));  // 8  — add5 remembers x = 5
console.log(add10(3)); // 13 — add10 remembers x = 10

function createCounter(initialValue = 0) {
  let count = initialValue; // private — not accessible from outside

  return {
    increment() { count++; },
    decrement() { count--; },
    reset()     { count = initialValue; },
    value()     { return count; },
  };
}

const c = createCounter(10);
c.increment();
c.increment();
console.log(c.value()); // 12
