// Angular component — closures in methods
@Component({ selector: 'app-timer', template: '<p>{{ elapsed }}s</p>' })
export class TimerComponent implements OnInit, OnDestroy {
  elapsed = 0;
  private intervalId: ReturnType<typeof setInterval> | null = null;

  ngOnInit() {
    // The arrow function closes over 'this' (the component instance)
    this.intervalId = setInterval(() => {
      this.elapsed++;   // 'this' is captured correctly via arrow function
    }, 1000);
  }

  ngOnDestroy() {
    if (this.intervalId !== null) clearInterval(this.intervalId);
    // If we didn't store intervalId, the closure would keep the component
    // alive in memory even after it is destroyed — a closure memory leak
  }
}

// Angular service — good naming
@Injectable({ providedIn: 'root' })
export class ProductService {
  private readonly API_URL = '/api/products';    // const-like; could also be module-level
  private cache = new Map<string, Product>();    // private field, camelCase

  getById(id: string): Observable<Product> {   // public method, camelCase
    const cacheKey = `product-${id}`;          // local const
    if (this.cache.has(cacheKey)) {
      return of(this.cache.get(cacheKey)!);
    }
    return this.http.get<Product>(`${this.API_URL}/${id}`);
  }
}

