const message = 'global';

function outer() {
  const message = 'outer'; // shadows the module-level message
  function inner() {
    const message = 'inner'; // shadows outer's message
    console.log(message);    // 'inner'
  }
  inner();
  console.log(message);      // 'outer'
}

