@Component({
  selector: 'app-search',
  template: `<input (input)="onSearch($event)"> <p>{{ resultCount }} results</p>`,
})
export class SearchComponent {
  resultCount = 0;         // class field — mutable state
  readonly pageSize = 20; // class field — fixed per instance

  constructor(private readonly searchService: SearchService) {}

  onSearch(event: Event) {
    const query = (event.target as HTMLInputElement).value; // local const — method scope
    if (!query.trim()) return;
    this.searchService.search(query).subscribe(results => {
      this.resultCount = results.length; // update class field
    });
  }
}

@Component({ ... })
export class ProductListComponent implements OnInit {
  products: Product[] = [];
  private readonly destroy$ = new Subject<void>();

  ngOnInit() {
    const PAGE_SIZE = 20; // closes over this in the operator chain

    this.productService.products$.pipe(
      map(all => all.slice(0, PAGE_SIZE)), // PAGE_SIZE from outer scope
      takeUntil(this.destroy$),
    ).subscribe(products => {
      this.products = products; // 'this' captured via arrow function closure
    });
  }

  ngOnDestroy() { this.destroy$.next(); this.destroy$.complete(); }
}

// Angular 15+ functional guard — clear, closed-over injection
export const authGuard = () => {
  const authService = inject(AuthService);
  const router = inject(Router);

  return authService.isLoggedIn() || router.createUrlTree(['/login']);
};

